"use client";
import { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { CheckCircle, XCircle, Loader2 } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function AdminPanel() {
  const { user, token } = useContext(AuthContext);
  const [pendingPosts, setPendingPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    // 1. הגנה על העמוד: אם המשתמש לא מחובר או שהוא לא אדמין, נזרוק אותו לעמוד הבית
    if (!token && !user) {
      setLoading(false);
      return;
    }
    
    if (user && user.role !== 'admin') {
      router.push('/');
      return;
    }

    // 2. משיכת הפוסטים הממתינים מהשרת (תוך כדי שליחת הטוקן לאבטחה)
    const fetchPendingPosts = async () => {
      try {
        const res = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/pending`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setPendingPosts(res.data);
      } catch (error) {
        console.error("שגיאה במשיכת פוסטים ממתינים:", error);
      } finally {
        setLoading(false);
      }
    };

    if (token) {
      fetchPendingPosts();
    }
  }, [user, token, router]);

  // 3. פונקציה לעדכון סטטוס (אישור או דחייה)
  const handleStatusUpdate = async (id, newStatus) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}/status`,
        { status: newStatus },
        { headers: { Authorization: `Bearer ${token}` } } // שולחים את הטוקן לאימות
      );
      
      // מסירים את הפוסט מהרשימה שמוצגת על המסך לאחר שעודכן
      setPendingPosts(prevPosts => prevPosts.filter(post => post._id !== id));
    } catch (error) {
      alert('שגיאה בעדכון הסטטוס. ודא שאתה מחובר כאדמין.');
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen bg-slate-50">
        <Loader2 className="w-12 h-12 animate-spin text-indigo-500" />
      </div>
    );
  }

  // במקרה שהיוזר לא אדמין, לא נציג לו כלום (הוא יועבר לעמוד הבית אוטומטית בגלל ה-useEffect)
  if (!user || user.role !== 'admin') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 text-xl font-bold text-rose-500">
        אין לך הרשאה לגשת לעמוד זה.
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-slate-50 py-12 px-8">
      <div className="max-w-5xl mx-auto">
        <h1 className="text-4xl font-black text-slate-900 mb-8 tracking-tight">
          פאנל ניהול <span className="text-rose-500">אישור פוסטים (AI)</span>
        </h1>
        
        {pendingPosts.length === 0 ? (
          <div className="bg-white p-10 rounded-2xl shadow-sm text-center border border-slate-100">
            <p className="text-xl text-slate-500">אין פוסטים הממתינים לאישור כרגע. סוכני ה-AI נחים! 😴</p>
          </div>
        ) : (
          <div className="flex flex-col gap-6">
            {pendingPosts.map(post => (
              <div key={post._id} className="bg-white p-6 rounded-2xl shadow-sm hover:shadow-md transition-shadow border border-slate-100 flex flex-col md:flex-row gap-6 items-start">
                
                {post.coverImage && (
                  <img src={post.coverImage} alt={post.title} className="w-full md:w-56 h-36 object-cover rounded-xl" />
                )}
                
                <div className="flex-grow">
                  <h2 className="text-2xl font-bold text-slate-800 mb-2">{post.title}</h2>
                  <p className="text-slate-600 mb-4 line-clamp-2">{post.content}</p>
                  
                  <div className="flex gap-4">
                    <button 
                      onClick={() => handleStatusUpdate(post._id, 'published')} 
                      className="flex items-center gap-2 bg-emerald-500 text-white px-5 py-2.5 rounded-xl hover:bg-emerald-600 transition font-medium"
                    >
                      <CheckCircle className="w-5 h-5" /> אשר ופרסם
                    </button>
                    <button 
                      onClick={() => handleStatusUpdate(post._id, 'rejected')} 
                      className="flex items-center gap-2 bg-rose-50 text-rose-600 px-5 py-2.5 rounded-xl hover:bg-rose-100 transition font-medium"
                    >
                      <XCircle className="w-5 h-5" /> דחה פוסט
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}